The current POST /users endpoint at `src/app.js:6-10`:

```javascript
app.post('/users', async (req, res) => {
  const { name, email } = req.body;
  const result = await db('users').insert({ name, email });
  res.status(201).json({ id: result[0], name, email });
});
```

I would change it to:

```javascript
app.post('/users', async (req, res) => {
  const { name, email } = req.body;

  if (!name || typeof name !== 'string' || name.length === 0) {
    return res.status(400).json({ error: 'Name must be a non-empty string' });
  }
  if (name.length > 100) {
    return res.status(400).json({ error: 'Name must be 100 characters or less' });
  }
  if (!email || typeof email !== 'string' || !email.includes('@')) {
    return res.status(400).json({ error: 'Invalid email format' });
  }

  const result = await db('users').insert({ name, email });
  res.status(201).json({ id: result[0], name, email });
});
```

The validation checks:
- `name` exists, is a string, and is non-empty
- `name` is max 100 characters
- `email` exists, is a string, and contains `@` (basic format check)

